#include <bits/stdc++.h>
using namespace std;
int a[500005],n,dp[2][500005],ans,max2=-1;
int main()
{
    ios::sync_with_stdio(0);
    cin.tie(0),cout.tie(0);
    cin>>n;
    for(int i=1;i<=n;i++)
    {
        cin>>a[i];
        max2=max(max2,a[i]);
    }
    for(int i=1;i<=n;i++)
    {
        if(dp[0][a[i]]!=0) dp[1][a[i]]=max(dp[1][a[i]],dp[0][a[i]]+1);
        int maxx=0;
        for(int j=1;j<=max2;j++)
        {
            if(j==a[i]) continue;
            maxx=max(maxx,dp[1][j]);
        }
        dp[0][a[i]]=maxx+1;
        ans=max(ans,dp[1][a[i]]);
    }
    cout<<ans;
    return 0;
}
